[createContinuousRenderer()](https://developers.arcgis.com/javascript/latest/references/core/smartMapping/renderers/size/#createContinuousRenderer) method.

```js
const sizeRendererCreator = await import("@arcgis/core/smartMapping/renderers/size.js");
const viewElement = document.querySelector("arcgis-map")!;
const sizeSlider = document.querySelector("arcgis-slider-size-legacy")!;

const featureLayer = new FeatureLayer({
  url: "https://services.arcgis.com/P3ePLMYs2RVChkJx/arcgis/rest/services/USA_Major_Cities_/FeatureServer/0",
});

await viewElement.viewOnReady();
viewElement.map?.add(featureLayer);

const params = {
  layer: featureLayer,
  view: viewElement.view,
  field: "POPULATION",
};

const rendererResult = await sizeRendererCreator.createContinuousRenderer(params);

featureLayer.renderer = rendererResult.renderer;

const histogramResult = await histogram({
  ...params,
  numBins: 30,
});

sizeSlider.updateFromRendererResult(rendererResult, histogramResult);
```

This slider should be used to update a [size visual variable](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/SizeVariable/)
in a layer's renderer. It is the responsibility of the app developer
to set up event listeners that update the size variable of the appropriate renderer.

```js
const updateRendererFromSlider = () => {
  const renderer = featureLayer.renderer?.clone();
  if (!renderer || !("visualVariables" in renderer) || !renderer.visualVariables?.[0]) {
    return;
  }

  const sizeVariable = renderer.visualVariables[0];
  const updatedSizeVariable = sizeSlider.updateVisualVariable(sizeVariable);
  if (!updatedSizeVariable) {
    return;
  }

  renderer.visualVariables = [updatedSizeVariable];
  featureLayer.renderer = renderer;
};

sizeSlider.addEventListener("arcgisThumbChange", updateRendererFromSlider);
sizeSlider.addEventListener("arcgisThumbDrag", updateRendererFromSlider);
sizeSlider.addEventListener("arcgisPropertyChange", updateRendererFromSlider);
```
